<h1><%= @post.title %></h1>

<div class="post-body">
  <%= raw @post.content %>
</div>

<div class="post-meta">
  <p>Author: <%= @post.author.name %></p>
  <p>Published on: <%= @post.inserted_at %></p>
</div>